import React, { useState, useEffect, useRef, useLayoutEffect } from "react";
import { useNavigate } from "react-router-dom";
import { User, Moon, Sun, Bell, Shield, Lock, Eye, EyeOff, ChevronRight, Monitor } from "lucide-react";
import api from "../../api.js";
import "../dashboard/Dashboard.css";

export default function SettingsPage() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));
  const [theme, setTheme] = useState(localStorage.getItem("ll_theme") || "dark");
  const [notifications, setNotifications] = useState({
    caseAssigned: JSON.parse(localStorage.getItem("ll_notif_caseAssigned") ?? "true"),
    evidenceUploaded: JSON.parse(localStorage.getItem("ll_notif_evidenceUploaded") ?? "true"),
    statusChanged: JSON.parse(localStorage.getItem("ll_notif_statusChanged") ?? "true"),
    auditAlerts: JSON.parse(localStorage.getItem("ll_notif_auditAlerts") ?? "true"),
  });
  const [privacy, setPrivacy] = useState({
    showEmail: JSON.parse(localStorage.getItem("ll_priv_showEmail") ?? "false"),
    twoFactor: JSON.parse(localStorage.getItem("ll_priv_twoFactor") ?? "false"),
    sessionTimeout: localStorage.getItem("ll_priv_timeout") || "60",
  });
  const [changePassForm, setChangePassForm] = useState({ current: "", newPass: "", confirm: "" });
  const [showPassFields, setShowPassFields] = useState(false);
  const [passError, setPassError] = useState("");
  const [passSuccess, setPassSuccess] = useState("");
  const [showCurrentPass, setShowCurrentPass] = useState(false);
  const [showNewPass, setShowNewPass] = useState(false);
  const [saving, setSaving] = useState(false);
  const scrollPositionRef = useRef(0);

  const handleTogglePassFields = (show) => {
    if (show) {
      scrollPositionRef.current = window.scrollY;
      setShowPassFields(true);
      setPassError("");
      setPassSuccess("");
    } else {
      setShowPassFields(false);
      setPassError("");
      setPassSuccess("");
      setTimeout(() => {
        window.scrollTo({ top: scrollPositionRef.current, behavior: "auto" });
      }, 0);
    }
  };

  const applyTheme = (t) => {
    document.documentElement.setAttribute("data-theme", t);
    localStorage.setItem("ll_theme", t);
    setTheme(t);
  };

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
  }, []);

  useEffect(() => {
    if (showPassFields) {
      scrollPositionRef.current = window.scrollY;

      const preventScroll = () => {
        window.scrollTo(0, scrollPositionRef.current);
      };

      window.addEventListener("scroll", preventScroll, { passive: false });

      return () => {
        window.removeEventListener("scroll", preventScroll);
      };
    }
  }, [showPassFields]);

  useEffect(() => {
    return () => {
      document.body.style.overflow = "";
    };
  }, []);

  const saveNotifPref = (key, value) => {
    const updated = { ...notifications, [key]: value };
    setNotifications(updated);
    localStorage.setItem(`ll_notif_${key}`, JSON.stringify(value));
  };

  const savePrivacyPref = (key, value) => {
    const updated = { ...privacy, [key]: value };
    setPrivacy(updated);
    localStorage.setItem(`ll_priv_${key}`, JSON.stringify(value));
  };

  const handleChangePassword = async () => {
    setPassError(""); setPassSuccess("");
    if (!changePassForm.current || !changePassForm.newPass) return setPassError("Please fill all fields");
    if (changePassForm.newPass !== changePassForm.confirm) return setPassError("Passwords do not match");
    if (changePassForm.newPass.length < 6) return setPassError("Password must be at least 6 characters");
    setSaving(true);
    try {
      await api.post("/change-password", { currentPassword: changePassForm.current, newPassword: changePassForm.newPass });
      setPassSuccess("Password changed successfully!");
      setChangePassForm({ current: "", newPass: "", confirm: "" });
      setShowPassFields(false);
    } catch (err) {
      setPassError(err.response?.data?.message || "Failed to change password");
    } finally {
      setSaving(false);
    }
  };

  const ToggleSwitch = ({ value, onChange }) => (
    <button
      type="button"
      onClick={() => onChange(!value)}
      style={{
        width: 44, height: 24, borderRadius: 12, border: "none", cursor: "pointer",
        background: value ? "#4f46e5" : "rgba(100,116,139,0.3)",
        position: "relative", transition: "background 0.2s", flexShrink: 0
      }}
    >
      <span style={{
        position: "absolute", top: 3, left: value ? "calc(100% - 21px)" : 3,
        width: 18, height: 18, borderRadius: "50%", background: "white", transition: "left 0.2s"
      }} />
    </button>
  );

  const SettingRow = ({ icon, title, description, children }) => (
    <div className="settingRow">
      <div className="settingRowLeft">
        <div className="settingRowIcon">{icon}</div>
        <div>
          <p className="settingRowTitle">{title}</p>
          {description && <p className="settingRowDesc">{description}</p>}
        </div>
      </div>
      <div className="settingRowRight">{children}</div>
    </div>
  );

  const SectionCard = ({ title, dot, children }) => (
    <div className="formSectionCard" style={{ marginBottom: "1.5rem" }}>
      <div className="sectionHeader">
        <div className="indicatorDot" style={{ background: dot || "#3b82f6" }} />
        <h2>{title}</h2>
      </div>
      <div style={{ padding: "0.5rem 0" }}>{children}</div>
    </div>
  );

  return (
    <div className="dashboardMain">
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText"><span>LEGALLENS</span> Settings</h1>
          <p className="systemStatus">Manage your preferences and account settings</p>
        </div>
      </header>

      <div style={{ maxWidth: 760 }}>

        {/* Profile Quick Access */}
        <SectionCard title="PROFILE" dot="#818cf8">
          <div
            className="settingRow settingRowClickable"
            onClick={() => navigate("/profile")}
            style={{ cursor: "pointer" }}
          >
            <div className="settingRowLeft">
              <div className="avatarCircle" style={{ width: 44, height: 44, fontSize: 18, background: "linear-gradient(135deg, #4f46e5, #9333ea)" }}>
                {user?.avatar ? (
                  <img src={`http://localhost:5000${user.avatar}`} alt="" style={{ width: "100%", height: "100%", borderRadius: "50%", objectFit: "cover" }} />
                ) : (
                  user?.name?.charAt(0)?.toUpperCase()
                )}
              </div>
              <div>
                <p className="settingRowTitle">{user?.name || "User"}</p>
                <p className="settingRowDesc">{user?.email} · {user?.role_name?.replace(/_/g, " ")}</p>
              </div>
            </div>
            <div className="settingRowRight" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
              <span style={{ fontSize: "0.8rem", color: "#818cf8" }}>Edit Profile</span>
              <ChevronRight size={16} color="#818cf8" />
            </div>
          </div>
        </SectionCard>

        {/* Appearance */}
        <SectionCard title="APPEARANCE" dot="#34d399">
          <SettingRow
            icon={<Monitor size={18} color="#94a3b8" />}
            title="Theme"
            description="Choose your preferred color scheme"
          >
            <div className="themeSelector">
              {[
                { value: "dark", icon: <Moon size={14} />, label: "Dark" },
                { value: "light", icon: <Sun size={14} />, label: "Light" },
              ].map((t) => (
                <button
                  type="button"
                  key={t.value}
                  onClick={() => applyTheme(t.value)}
                  className={`themeBtn ${theme === t.value ? "themeBtnActive" : ""}`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>
          </SettingRow>
        </SectionCard>

        {/* Notifications */}
        <SectionCard title="NOTIFICATIONS" dot="#fbbf24">
          {[
            { key: "caseAssigned", title: "Case Assigned", desc: "When you are assigned to a new case" },
            { key: "evidenceUploaded", title: "Evidence Uploaded", desc: "When new evidence is added to your cases" },
            { key: "statusChanged", title: "Status Changes", desc: "When a case status is updated" },
            ...(user?.role_id === 1 ? [{ key: "auditAlerts", title: "Audit Alerts", desc: "Critical system activity alerts" }] : []),
          ].map(({ key, title, desc }) => (
            <SettingRow key={key} icon={<Bell size={18} color="#94a3b8" />} title={title} description={desc}>
              <ToggleSwitch value={notifications[key]} onChange={(v) => saveNotifPref(key, v)} />
            </SettingRow>
          ))}
        </SectionCard>

        {/* Privacy & Security */}
        <SectionCard title="PRIVACY & SECURITY" dot="#f87171">
          <SettingRow
            icon={<Eye size={18} color="#94a3b8" />}
            title="Show Email to Team"
            description="Other members can see your email address"
          >
            <ToggleSwitch value={privacy.showEmail} onChange={(v) => savePrivacyPref("showEmail", v)} />
          </SettingRow>

          <SettingRow
            icon={<Shield size={18} color="#94a3b8" />}
            title="Session Timeout"
            description="Auto logout after inactivity"
          >
            <select
              value={privacy.sessionTimeout}
              onChange={(e) => savePrivacyPref("sessionTimeout", e.target.value)}
              className="modalInput" style={{ padding: "0.4rem 0.75rem", fontSize: "0.85rem", width: "auto" }}
            >
              {[15, 30, 60, 120, 240].map((v) => (
                <option key={v} value={String(v)}>{v < 60 ? `${v} minutes` : `${v / 60} hour${v > 60 ? "s" : ""}`}</option>
              ))}
            </select>
          </SettingRow>

          {/* Change Password */}
          <SettingRow
            icon={<Lock size={18} color="#94a3b8" />}
            title="Change Password"
            description="Update your account password"
          >
            <button
              type="button"
              className="secondaryActionBtn"
              style={{ padding: "0.4rem 1rem", width: "auto", fontSize: "0.8rem" }}
              onClick={(e) => { e.preventDefault(); handleTogglePassFields(!showPassFields); }}
            >
              {showPassFields ? "Cancel" : "Change"}
            </button>
          </SettingRow>

          {showPassFields && (
            <div style={{ padding: "1rem 2rem", borderTop: "1px solid rgba(255,255,255,0.05)" }}>
              {passError && <div className="alertBanner alertError">{passError}</div>}
              {passSuccess && <div className="alertBanner alertSuccess">{passSuccess}</div>}
              <div className="formGrid" style={{ gridTemplateColumns: "1fr", gap: "1rem" }}>
                {[
                  { label: "Current Password", key: "current", show: showCurrentPass, toggle: () => setShowCurrentPass((v) => !v) },
                  { label: "New Password", key: "newPass", show: showNewPass, toggle: () => setShowNewPass((v) => !v) },
                  { label: "Confirm New Password", key: "confirm", show: showNewPass, toggle: null },
                ].map(({ label, key, show, toggle }) => (
                  <div key={key} className="inputGroup">
                    <label>{label}</label>
                    <div style={{ position: "relative" }}>
                      <input
                        type={show ? "text" : "password"}
                        value={changePassForm[key]}
                        onChange={(e) => { 
                          setChangePassForm((p) => ({ ...p, [key]: e.target.value }));
                          window.scrollTo(0, scrollPositionRef.current);
                        }}
                        onKeyDown={(e) => {
                          scrollPositionRef.current = window.scrollY;
                        }}
                        onWheel={(e) => {
                          e.preventDefault();
                        }}
                        placeholder={`Enter ${label.toLowerCase()}`}
                        style={{ paddingRight: "2.5rem", width: "100%" }}
                      />
                      {toggle && (
                        <button type="button" onClick={(e) => { e.preventDefault(); toggle(); }} style={{ position: "absolute", right: "0.75rem", top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: "#475569", cursor: "pointer" }}>
                          {show ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                      )}
                    </div>
                  </div>
                ))}
                <div style={{ display: "flex", gap: "1rem", marginTop: "0.5rem" }}>
                  <button type="button" className="btnCreate" onClick={(e) => { e.preventDefault(); handleChangePassword(); }} disabled={saving}>
                    {saving ? "Saving..." : "Update Password"}
                  </button>
                </div>
              </div>
            </div>
          )}
        </SectionCard>

        {/* System Info */}
        <SectionCard title="SYSTEM INFO" dot="#475569">
          {[
            { label: "Version", value: "LegalLens v1.0.0" },
            { label: "Role", value: user?.role_name?.replace(/_/g, " ") },
            { label: "User ID", value: user?.id?.slice(-8)?.toUpperCase() },
            { label: "Session", value: "Active" },
          ].map(({ label, value }) => (
            <div key={label} className="settingRow">
              <p className="settingRowTitle" style={{ color: "#64748b" }}>{label}</p>
              <p style={{ color: label === "Session" ? "#34d399" : "#94a3b8", fontSize: "0.875rem", fontFamily: label === "User ID" ? "monospace" : "inherit" }}>{value}</p>
            </div>
          ))}
        </SectionCard>

      </div>
    </div>
  );
}
